254	/**
255	 * KRN-09 — kind of substitution applied to a curtain-wall grid cell.
256	 *
257	 * - `empty`: leave the cell open (no glass, no solid panel; mullions stay).
258	 * - `system`: render the cell as a solid panel using a registered
259	 *   `materialKey`. Falls back to glass if no `materialKey` is supplied.
260	 * - `family_instance`: instantiate a custom family at this cell. Until
261	 *   FAM-01 lands the renderer paints a placeholder panel and emits a TODO.
262	 */
263	export type CurtainPanelOverrideKind = 'empty' | 'system' | 'family_instance';
264	
265	export type CurtainPanelOverride = {
266	  kind: CurtainPanelOverrideKind;
267	  /** For `family_instance` overrides — id of the family type to instantiate. */
268	  familyTypeId?: string | null;
269	  /** For `system` overrides — `materialKey` resolved against the MAT-01 registry. */
270	  materialKey?: string | null;
271	};
