297	   * matches inside source models too; `{ specificLinkId }` restricts to one
298	   * link. Linked element AABBs are transformed by the link's positionMm +
299	   * rotationDeg before clash-checking.
300	   */
301	  linkScope?: 'host' | 'all_links' | { specificLinkId: string };
