332	   * elements; otherwise a single-element array `[linkId]` identifying the
333	   * `link_model` row whose source contains the element. (Multi-hop transitive
334	   * links are deferred — the FED-01 expander is single-hop only.)
335	   */
336	  linkChainA?: string[];
337	  linkChainB?: string[];
338	};
